(170, 'Appartement', 3, 2, 91.95, 'Le Cannet', 'Le Cannet', 413000, 'Grand 3 pièces — Parking & Cave', 'Spacieux appartement de 91.95 m², idéalement situé proche des commerces, à 10 minutes du centre de Cannes. Grande entrée, dressings, cuisine équipée fermée, vaste séjour salon.', ARRAY['Parking', 'Cave', 'Proche Cannes'], 'https://www.agencerossicroisette.com/vente/9-le-cannet/appartement/170-le-cannet-grand-3-pieces-parking-et-cave', 'grad-1', false),
(169, 'Appartement', 1, 0, 20, 'Cannes', 'Basse Californie', 195000, 'Studio — Cave, Parking & Terrasse', 'Studio de 20 m² dans une charmante copropriété proche des commerces. Cuisine équipée, belle terrasse de 12 m², salle de douche. Parking et cave inclus.', ARRAY['Terrasse 12m²', 'Parking', 'Cave'], 'https://www.agencerossicroisette.com/vente/1-cannes/appartement/169-cannes-basse-californie-studio-cave-parking-terrasse', 'grad-2', false),
(163, 'Appartement', 3, 2, 47, 'Cannes', 'La Croisette', 1260000, '3 pièces Croisette — Balcon, Vue Mer, Rénové', 'Sur la célèbre Croisette, entièrement rénové avec des prestations modernes. 3ᵉ étage, belle luminosité, terrasse de 7 m² avec vue mer partielle.', ARRAY['Vue mer', 'Terrasse 7m²', 'Rénové', 'Croisette'], 'https://www.agencerossicroisette.com/vente/1-cannes/appartement/163-a-vendre-cannes-croisette-3-pieces-2-chambres-balcon-renove', 'grad-3', true),
(156, 'Appartement', 2, 1, 36.16, 'Cannes', 'La Croisette', 760000, '2 pièces Croisette 1ère ligne — Vue Panoramique Mer', 'Croisette première ligne, magnifique 2 pièces de 36 m². Hall d\'entrée avec dressing, cuisine séparée équipée, séjour donnant sur terrasse de 7 m², vue panoramique sur la baie.', ARRAY['Vue mer panoramique', 'Terrasse 7m²', '1ère ligne', 'Parking'], 'https://www.agencerossicroisette.com/vente/1-cannes/appartement/156-cannes-croisette-vue-panoramique-mer', 'grad-4', true),
(154, 'Appartement', 3, 2, 75, 'Cannes', 'La Croisette', 1590000, '3 pièces Croisette — Rénové, Parking, Terrasse', 'Magnifique 3 pièces de 75 m² sur la célébre Croisette. Proche des plages, restaurants, Palais des Festivals. Rénové, parking extérieur inclus.', ARRAY['Croisette', 'Terrasse', 'Parking', 'Rénové'], 'https://www.agencerossicroisette.com/vente/1-cannes/appartement/154-a-vendre-cannes-croisette-3-pieces-2-chambres-renove-parking-exterieur-terrasse', 'grad-5', true),
(153, 'Appartement', 3, 2, 57, 'Cannes', 'Basse Californie', 450000, '3 pièces — Balcon, Terrasse & Cave', 'Secteur Basse Californie, à quelques minutes du centre-ville, des commerces, de la plage et de la Croisette. 3 pièces partiellement rénové avec balcon et terrasse.', ARRAY['Balcon', 'Terrasse', 'Cave', 'Basse Californie'], 'https://www.agencerossicroisette.com/vente/1-cannes/appartement/153-a-vendre-cannes-3-pieces-2-chambres-renove-balcon-terrasse-cave', 'grad-6', false),
(152, 'Appartement', 4, 3, 157.9, 'Cannes', 'Centre-Ville', 1375000, '4 pièces Art-Déco — 157 m², Rénové', 'À quelques minutes à pied des plages et du centre-ville, magnifique 4 pièces Art-Déco de 157.9 m². Double séjour, salle à manger, cuisine équipée.', ARRAY['157 m²', 'Art-Déco', 'Rénové', 'Grand Volume'], 'https://www.agencerossicroisette.com/vente/1-cannes/appartement/152-a-vendre-cannes-art-deco-4p-3-chambres-renove', 'grad-1', true),
(151, 'Appartement', 3, 2, 74.37, 'Cannes', 'Basse Californie', 780000, '3 pièces — Terrasse Vue Mer, Garage & Cave', 'Dans un écrin de verdure, proche des plages, dans une très belle résidence avec gardien. Appartement entièrement rénové, grand séjour, terrasse avec vue mer.', ARRAY['Vue mer', 'Terrasse', 'Garage', 'Cave', 'Gardien'], 'https://www.agencerossicroisette.com/vente/1-cannes/appartement/151-vente-cannes-basse-californie-3pces-terrasse-vue-mer-garage-cave', 'grad-2', false),
(150, 'Maison', 7, 4, 315, 'Cannes', 'La Californie', 6970000, 'Villa-Appartement 315 m² — Vue Mer, Parc 2 ha', 'Villa-appartement lumineuse de 7 pièces dans le secteur de la Californie. Implantée dans un parc paysager de 2 hectares, rénovée par un architecte de renom. Vue panoramique.', ARRAY['315 m²', 'Vue mer panoramique', 'Parc 2 ha', 'Architecte'], 'https://www.agencerossicroisette.com/vente/1-cannes/maison/150-a-vendre-cannes-villa-appartement-vue-mer-315-m2', 'grad-3', true),
(149, 'Appartement', 4, 3, 110, 'Cannes', 'La Croisette', 2580000, '4 pièces Croisette — Dernier Étage, Vue Mer', 'Un appartement rénové d\'exception sur la Croisette. 4 pièces de 110 m² perché au dernier étage, vue imprenable sur la mer. Vaste séjour baigné de lumière avec terrasse.', ARRAY['Dernier étage', 'Vue mer', 'Croisette', '110 m²', 'Terrasse'], 'https://www.agencerossicroisette.com/vente/1-cannes/appartement/149-a-vendre-cannes-croisette-4-p-dernier-etage-vue-mer-panoramique', 'grad-4', true),
(148, 'Appartement', 5, 4, 118, 'Cannes', 'Roi Albert', 2480000, '5 pièces Roi Albert — Vue Mer Panoramique', 'Magnifique propriété offrant une vue panoramique sur la Méditerranée. Entièrement rénové avec des matériaux de haute qualité. 5 pièces spacieuses dans une résidence de prestige.', ARRAY['Vue mer panoramique', '118 m²', 'Matériaux luxe', 'Rénové'], 'https://www.agencerossicroisette.com/vente/1-cannes/appartement/148-a-vendre-cannes-roi-albert-5-pieces-vue-mer', 'grad-5', true),
(147, 'Appartement', 4, 3, 92, 'Cannes', 'La Californie', 2580000, '4 pièces Californie — 6ème Étage, Vue Mer Panoramique', 'Dans une belle résidence de standing, 4 pièces de 92 m² au 6ème étage with vue mer panoramique. 3 chambres en suite, cuisine ouverte, belle terrasse.', ARRAY['6ème étage', 'Vue mer', '3 suites', 'Californie', 'Terrasse'], 'https://www.agencerossicroisette.com/vente/1-cannes/appartement/147-a-vendre-superbe-4-pieces-vue-mer-panoramique-secteur-californie', 'grad-6', true),
