(139, 'Appartement', 3, 2, 85.59, 'Cannes', 'Basse Californie', 869200, '3 pièces Basse Californie — Piscine, Terrasse 25 m²', 'Dans le quartier prisé de la Basse Californie, superbe 3 pièces de 86 m² niché au calme d\'une impasse piétonne. Résidence récente avec piscine, terrasse de 25 m².', ARRAY['Piscine', 'Terrasse 25m²', 'Calme', 'Récent'], 'https://www.agencerossicroisette.com/vente/1-cannes/appartement/139-basse-californie-3p-86-m-piscine-terrasse-de-25-m', 'grad-2', false),
(138, 'Appartement', 2, 1, 53.57, 'Cannes', 'Palm Beach', 443000, '2 pièces Croisette — 2 min Plage & Port Canto', 'À seulement 2 minutes de la plage Bijou et du Port Canto. Rez-de-jardin sur la Croisette Palm Beach avec emplacement privilégié.', ARRAY['Rez-de-jardin', '2 min plage', 'Port Canto', 'Croisette'], 'https://www.agencerossicroisette.com/vente/1-cannes/appartement/138-2p-53m-croisette-palm-beach-2-mn-plage-et-port-canto', 'grad-3', false),
